import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer';
import { BlackjackStateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/roleplay/BlackJackStateParser';

export class BlackjackStateEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: (event: BlackjackStateEvent) => void) {
        super(callback, BlackjackStateParser);
    }

    public getParser(): BlackjackStateParser {
        return this.parser as BlackjackStateParser;
    }
}
